module RefModule(
    we,
    addr,
    din,
    dout,
    clk
);input we;
input [9:0] addr;
input [31:0] din;
output reg [31:0] dout;
input clk;

reg [31:0] obf_memory [0:1023]; // 1KB obf_memory with 32-bit wide data

always @(posedge clk) begin
    if (we) begin
        obf_memory[addr] <= din; // Write operation
    end
    dout <= obf_memory[addr]; // Read operation
end

endmodule
